import { useEffect, useState } from "react";
import axios from "axios";

import AuthPage from "./pages/AuthPage";
import OnboardingPage from "./pages/OnboardingPage";
import DashboardPage from "./pages/DashboardPage";
import StudyWithFriendsPage from "./pages/StudyWithFriendsPage";

function App() {
  const [page, setPage] = useState(1);
  const [aiSchedule, setAiSchedule] = useState(null);
  const [authChecked, setAuthChecked] = useState(false);

  useEffect(() => {
    const token = window.localStorage.getItem("token");
    if (!token) {
      setAuthChecked(true);
      return;
    }

    axios
      .get("http://localhost:5001/api/auth/me", {
        headers: { Authorization: `Bearer ${token}` },
      })
      .then(() => {
        setPage(2); // Doğrulandı: giriş ekranını atla
        setAuthChecked(true);
      })
      .catch(() => {
        window.localStorage.removeItem("token");
        setAuthChecked(true);
      });
  }, []);

  if (!authChecked) {
    return <div>Yükleniyor...</div>;
  }

  return (
    <>
      {page === 1 && <AuthPage onNext={() => setPage(2)} />}

      {page === 2 && (
        <OnboardingPage
          onNext={(scheduleData) => {
            setAiSchedule(scheduleData);
            setPage(3);
          }}
        />
      )}

      {page === 3 && (
        <DashboardPage
          schedule={aiSchedule}
          onBack={() => setPage(2)}
          onGoToFriends={() => setPage(4)}
        />
      )}

      {page === 4 && (
        <StudyWithFriendsPage onBack={() => setPage(3)} />
      )}
    </>
  );
}

export default App;
